package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertThrows;
import static org.mockito.Mockito.mock;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testValidate() {
        CSVFormat csvFormat = new CSVFormat(',', '\"', QuoteMode.ALL, '#', '\\', true, false, "\r\n", null, new String[]{"Header1", "Header2"}, true, true);

        assertThrows(IllegalArgumentException.class, csvFormat::validate);

        csvFormat = new CSVFormat(',', '\"', QuoteMode.ALL, null, '\\', true, false, "\r\n", null, new String[]{"Header1", "Header2"}, true, true);

        assertThrows(IllegalArgumentException.class, csvFormat::validate);

        csvFormat = new CSVFormat(',', '\"', QuoteMode.ALL, '\"', '\\', true, false, "\r\n", null, new String[]{"Header1", "Header2"}, true, true);

        assertThrows(IllegalArgumentException.class, csvFormat::validate);

        csvFormat = new CSVFormat(',', '\"', QuoteMode.ALL, '#', '#', true, false, "\r\n", null, new String[]{"Header1", "Header2"}, true, true);

        assertThrows(IllegalArgumentException.class, csvFormat::validate);

        csvFormat = new CSVFormat(',', '\"', QuoteMode.ALL, '#', '#', true, false, "\r\n", null, new String[]{"Header1", "Header2"}, false, true);

        assertThrows(IllegalArgumentException.class, csvFormat::validate);

        csvFormat = new CSVFormat(',', '\"', QuoteMode.ALL, '#', '#', null, false, "\r\n", null, new String[]{"Header1", "Header2"}, false, true);

        assertThrows(IllegalArgumentException.class, csvFormat::validate);
    }
}
